from notebookutils import mssparkutils

def get_table_location(source_table):
    """Gets the data path from managed table metadata."""
    desc_df = spark.sql(f"DESCRIBE EXTENDED {source_table}")
    location_row = desc_df.filter("col_name = 'Location'").collect()
    if not location_row:
        raise ValueError(f"Could not find Location for: {source_table}")
    return location_row[0]["data_type"].strip()


def get_table_type(source_table):
    """Returns MANAGED or EXTERNAL."""
    desc_df = spark.sql(f"DESCRIBE EXTENDED {source_table}")
    type_row = desc_df.filter("col_name = 'Type'").collect()
    if type_row:
        return type_row[0]["data_type"].strip().upper()
    return "UNKNOWN"


def detect_table_format(source_table, data_path):
    """Detects Delta or Parquet using multiple methods."""
    try:
        desc_df = spark.sql(f"DESCRIBE EXTENDED {source_table}")
        provider_row = desc_df.filter(
            "col_name = 'Provider' OR col_name = 'Serde Library' OR col_name = 'InputFormat'"
        ).collect()
        for row in provider_row:
            val = str(row["data_type"]).lower()
            if "delta" in val:
                return "DELTA"
    except Exception:
        pass

    try:
        files = mssparkutils.fs.ls(data_path)
        for f in files:
            if f.name == "_delta_log" or f.name == "_delta_log/":
                return "DELTA"
    except Exception:
        pass

    try:
        spark.read.format("delta").load(data_path).limit(1).collect()
        return "DELTA"
    except Exception:
        pass

    return "PARQUET"


def get_partition_columns(source_table):
    """
    Detects partition columns from table metadata.
    Returns list of partition column names, empty list if not partitioned.
    """
    partition_cols = []

    try:
        # Method 1: SHOW PARTITIONS (works for Hive-style partitioned tables)
        desc_df = spark.sql(f"DESCRIBE EXTENDED {source_table}")
        rows = desc_df.collect()

        # Find the '# Partition Information' section in DESCRIBE EXTENDED
        in_partition_section = False
        for row in rows:
            col_name = str(row["col_name"]).strip()
            data_type = str(row["data_type"]).strip() if row["data_type"] else ""

            if col_name == "# Partition Information":
                in_partition_section = True
                continue

            if in_partition_section:
                # End of partition section when we hit another # section or empty
                if col_name.startswith("#") or col_name == "" or col_name.startswith("# Detailed"):
                    break
                # Skip the header row "# col_name"
                if col_name == "# col_name":
                    continue
                if col_name and data_type:
                    partition_cols.append(col_name)
    except Exception:
        pass

    # Method 2: For Delta tables, check Delta table detail
    if not partition_cols:
        try:
            detail_df = spark.sql(f"DESCRIBE DETAIL {source_table}")
            detail_row = detail_df.collect()[0]
            part_cols = detail_row["partitionColumns"]
            if part_cols:
                partition_cols = list(part_cols)
        except Exception:
            pass

    return partition_cols


def get_table_metadata(source_table):
    """
    Returns all auto-detected metadata for a table as a dict.
    """
    data_path = get_table_location(source_table)
    return {
        "table": source_table,
        "path": data_path,
        "type": get_table_type(source_table),
        "format": detect_table_format(source_table, data_path),
        "partitions": get_partition_columns(source_table)
    }


